arguments.file_text:
@* Step progress indicator bar *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass"
                role="listitem"
                @onclick="() => OnStepClick(step)"
                @onclick:preventDefault
                style="@(isCompleted ? "cursor: pointer;" : "cursor: default;")">
                <span class="step-circle">
                    @if (isCompleted)
                    {
                        <span class="checkmark">&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: '';
    position: absolute;
    top: 18px;
    left: 24px;
    right: 24px;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    z-index: 1;
    flex: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.5rem;
    transition: all 0.2s;
}

.step.active .step-circle {
    background: #0d6efd;
    color: white;
    box-shadow: 0 0 0 4px rgba(13, 110, 253, 0.2);
}

.step.completed .step-circle {
    background: #198754;
    color: white;
}

.step.future .step-circle {
    background: #dee2e6;
    color: #6c757d;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    max-width: 80px;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.future .step-label {
    color: #adb5bd;
}

.checkmark {
    font-size: 1rem;
    line-height: 1;
}

@* Step progress indicator bar *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var cssClass = isCurrent ? "step active" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass"
                role="listitem"
                @onclick="() => OnStepClick(step)"
                @onclick:preventDefault
                style="@(isCompleted ? "cursor: pointer;" : "cursor: default;")">
                <span class="step-circle">
                    @if (isCompleted)
                    {
                        <span class="checkmark">&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
